// modules/files/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'files',
  description: 'Handles file uploads, storage, and retrieval utilities.',

  dependencies: { modules: [] },

  exposes: {
    routes: [
      { method: 'POST', path: '/files/upload', auth: true },
    ],
    functions: ['uploadFile'],
    types: ['File', 'FileError'],
  },

  sideEffects: [
    'writes to: files table',
    'uploads file to object storage',
  ],

  invariants: [
    'Each file must have a unique identifier',
    'Uploaded files must be stored securely and accessible via the provided URL',
    'File metadata must be accurately recorded in the database',
  ],
});

